47: class GDScriptDataType {
48: public:
49: 	Vector<GDScriptDataType> container_element_types;
50: 
51: 	enum Kind {
52: 		UNINITIALIZED,
53: 		BUILTIN,
54: 		NATIVE,
55: 		SCRIPT,
56: 		GDSCRIPT,
57: 	};
58: 
59: 	Kind kind = UNINITIALIZED;
60: 
61: 	bool has_type = false;
62: 	Variant::Type builtin_type = Variant::NIL;
63: 	StringName native_type;
64: 	Script *script_type = nullptr;
65: 	Ref<Script> script_type_ref;
66: 
67: 	bool is_type(const Variant &p_variant, bool p_allow_implicit_conversion = false) const {
68: 		if (!has_type) {
69: 			return true; // Can't type check
70: 		}
71: 
72: 		switch (kind) {
73: 			case UNINITIALIZED:
74: 				break;
75: 			case BUILTIN: {
76: 				Variant::Type var_type = p_variant.get_type();
77: 				bool valid = builtin_type == var_type;
78: 				if (valid && builtin_type == Variant::ARRAY && has_container_element_type(0)) {
79: 					Array array = p_variant;
80: 					if (array.is_typed()) {
81: 						const GDScriptDataType &elem_type = container_element_types[0];
82: 						Variant::Type array_builtin_type = (Variant::Type)array.get_typed_builtin();
83: 						StringName array_native_type = array.get_typed_class_name();
84: 						Ref<Script> array_script_type_ref = array.get_typed_script();
85: 
86: 						if (array_script_type_ref.is_valid()) {
87: 							valid = (elem_type.kind == SCRIPT || elem_type.kind == GDSCRIPT) && elem_type.script_type == array_script_type_ref.ptr();
88: 						} else if (array_native_type != StringName()) {
89: 							valid = elem_type.kind == NATIVE && elem_type.native_type == array_native_type;
90: 						} else {
91: 							valid = elem_type.kind == BUILTIN && elem_type.builtin_type == array_builtin_type;
92: 						}
93: 					} else {
94: 						valid = false;
95: 					}
96: 				} else if (!valid && p_allow_implicit_conversion) {
97: 					valid = Variant::can_convert_strict(var_type, builtin_type);
98: 				}
99: 				return valid;
100: 			} break;
101: 			case NATIVE: {
102: 				if (p_variant.get_type() == Variant::NIL) {
103: 					return true;
104: 				}
105: 				if (p_variant.get_type() != Variant::OBJECT) {
106: 					return false;
107: 				}
108: 
109: 				bool was_freed = false;
110: 				Object *obj = p_variant.get_validated_object_with_check(was_freed);
111: 				if (!obj) {
112: 					return !was_freed;
113: 				}
114: 
115: 				if (!ClassDB::is_parent_class(obj->get_class_name(), native_type)) {
116: 					return false;
117: 				}
118: 				return true;
119: 			} break;
120: 			case SCRIPT:
121: 			case GDSCRIPT: {
122: 				if (p_variant.get_type() == Variant::NIL) {
123: 					return true;
124: 				}
125: 				if (p_variant.get_type() != Variant::OBJECT) {
126: 					return false;
127: 				}
128: 
129: 				bool was_freed = false;
130: 				Object *obj = p_variant.get_validated_object_with_check(was_freed);
131: 				if (!obj) {
132: 					return !was_freed;
133: 				}
134: 
135: 				Ref<Script> base = obj && obj->get_script_instance() ? obj->get_script_instance()->get_script() : nullptr;
136: 				bool valid = false;
137: 				while (base.is_valid()) {
138: 					if (base == script_type) {
139: 						valid = true;
140: 						break;
141: 					}
142: 					base = base->get_base_script();
143: 				}
144: 				return valid;
145: 			} break;
146: 		}
147: 		return false;
148: 	}
149: 
150: 	bool can_contain_object() const {
151: 		if (has_type && kind == BUILTIN) {
152: 			switch (builtin_type) {
153: 				case Variant::ARRAY:
154: 					if (has_container_element_type(0)) {
155: 						return container_element_types[0].can_contain_object();
156: 					}
157: 					return true;
158: 				case Variant::DICTIONARY:
159: 				case Variant::NIL:
160: 				case Variant::OBJECT:
161: 					return true;
162: 				default:
163: 					return false;
164: 			}
165: 		}
166: 		return true;
167: 	}
168: 
169: 	void set_container_element_type(int p_index, const GDScriptDataType &p_element_type) {
170: 		ERR_FAIL_COND(p_index < 0);
171: 		while (p_index >= container_element_types.size()) {
172: 			container_element_types.push_back(GDScriptDataType());
173: 		}
174: 		container_element_types.write[p_index] = GDScriptDataType(p_element_type);
175: 	}
176: 
177: 	GDScriptDataType get_container_element_type(int p_index) const {
178: 		ERR_FAIL_INDEX_V(p_index, container_element_types.size(), GDScriptDataType());
179: 		return container_element_types[p_index];
180: 	}
181: 
182: 	GDScriptDataType get_container_element_type_or_variant(int p_index) const {
183: 		if (p_index < 0 || p_index >= container_element_types.size()) {
184: 			return GDScriptDataType();
185: 		}
186: 		return container_element_types[p_index];
187: 	}
188: 
189: 	bool has_container_element_type(int p_index) const {
190: 		return p_index >= 0 && p_index < container_element_types.size();
191: 	}
192: 
193: 	bool has_container_element_types() const {
194: 		return !container_element_types.is_empty();
195: 	}
196: 
197: 	GDScriptDataType() = default;
198: 
199: 	void operator=(const GDScriptDataType &p_other) {
200: 		kind = p_other.kind;
201: 		has_type = p_other.has_type;
202: 		builtin_type = p_other.builtin_type;
203: 		native_type = p_other.native_type;
204: 		script_type = p_other.script_type;
205: 		script_type_ref = p_other.script_type_ref;
206: 		container_element_types = p_other.container_element_types;
207: 	}
208: 
209: 	GDScriptDataType(const GDScriptDataType &p_other) {
210: 		*this = p_other;
211: 	}
212: 
213: 	~GDScriptDataType() {}
214: };
