112: Variant GDScriptFunction::_get_default_variant_for_data_type(const GDScriptDataType &p_data_type) {
113: 	if (p_data_type.kind == GDScriptDataType::BUILTIN) {
114: 		if (p_data_type.builtin_type == Variant::ARRAY) {
115: 			Array array;
116: 			// Typed array.
117: 			if (p_data_type.has_container_element_type(0)) {
118: 				const GDScriptDataType &element_type = p_data_type.get_container_element_type(0);
119: 				array.set_typed(element_type.builtin_type, element_type.native_type, element_type.script_type);
120: 			}
121: 
122: 			return array;
123: 		} else {
124: 			Callable::CallError ce;
125: 			Variant variant;
126: 			Variant::construct(p_data_type.builtin_type, variant, nullptr, 0, ce);
127: 
128: 			ERR_FAIL_COND_V(ce.error != Callable::CallError::CALL_OK, Variant());
129: 
130: 			return variant;
131: 		}
132: 	}
133: 
134: 	return Variant();
135: }
