105: 		case GDScriptParser::DataType::NATIVE: {
106: 			if (p_handle_metatype && p_datatype.is_meta_type) {
107: 				result.kind = GDScriptDataType::NATIVE;
108: 				result.builtin_type = Variant::OBJECT;
109: 				// Fixes GH-82255. `GDScriptNativeClass` is obtainable in GDScript,
110: 				// but is not a registered and exposed class, so `GDScriptNativeClass`
111: 				// is missing from `GDScriptLanguage::get_singleton()->get_global_map()`.
112: 				//result.native_type = GDScriptNativeClass::get_class_static();
113: 				result.native_type = Object::get_class_static();
114: 				break;
115: 			}
116: 
117: 			result.kind = GDScriptDataType::NATIVE;
118: 			result.builtin_type = p_datatype.builtin_type;
119: 			result.native_type = p_datatype.native_type;
120: 
121: #ifdef DEBUG_ENABLED
122: 			if (unlikely(!GDScriptLanguage::get_singleton()->get_global_map().has(result.native_type))) {
123: 				ERR_PRINT(vformat(R"(GDScript bug: Native class "%s" not found.)", result.native_type));
124: 				result.native_type = Object::get_class_static();
125: 			}
126: #endif
127: 		} break;
128: 		case GDScriptParser::DataType::SCRIPT: {
129: 			if (p_handle_metatype && p_datatype.is_meta_type) {
130: 				result.kind = GDScriptDataType::NATIVE;
131: 				result.builtin_type = Variant::OBJECT;
132: 				result.native_type = p_datatype.script_type.is_valid() ? p_datatype.script_type->get_class() : Script::get_class_static();
133: 				break;
134: 			}
135: 
136: 			result.kind = GDScriptDataType::SCRIPT;
137: 			result.builtin_type = p_datatype.builtin_type;
138: 			result.script_type_ref = p_datatype.script_type;
139: 			result.script_type = result.script_type_ref.ptr();
140: 			result.native_type = p_datatype.native_type;
141: 		} break;
142: 		case GDScriptParser::DataType::CLASS: {
143: 			if (p_handle_metatype && p_datatype.is_meta_type) {
144: 				result.kind = GDScriptDataType::NATIVE;
145: 				result.builtin_type = Variant::OBJECT;
146: 				result.native_type = GDScript::get_class_static();
147: 				break;
148: 			}
149: 
150: 			result.kind = GDScriptDataType::GDSCRIPT;
151: 			result.builtin_type = p_datatype.builtin_type;
152: 			result.native_type = p_datatype.native_type;
153: 
154: 			bool is_local_class = parser->has_class(p_datatype.class_type);
155: 
156: 			Ref<GDScript> script;
157: 			if (is_local_class) {
158: 				script = Ref<GDScript>(main_script);
159: 			} else {
160: 				Error err = OK;
161: 				script = GDScriptCache::get_shallow_script(p_datatype.script_path, err, p_owner->path);
162: 				if (err) {
163: 					_set_error(vformat(R"(Could not find script "%s": %s)", p_datatype.script_path, error_names[err]), nullptr);
164: 				}
165: 			}
166: 
167: 			if (script.is_valid()) {
168: 				script = Ref<GDScript>(script->find_class(p_datatype.class_type->fqcn));
169: 			}
170: 
171: 			if (script.is_null()) {
172: 				_set_error(vformat(R"(Could not find class "%s" in "%s".)", p_datatype.class_type->fqcn, p_datatype.script_path), nullptr);
173: 				return GDScriptDataType();
174: 			} else {
175: 				// Only hold a strong reference if the owner of the element qualified with this type is not local, to avoid cyclic references (leaks).
176: 				// TODO: Might lead to use after free if script_type is a subclass and is used after its parent is freed.
177: 				if (!is_local_class) {
178: 					result.script_type_ref = script;
179: 				}
180: 				result.script_type = script.ptr();
181: 				result.native_type = p_datatype.native_type;
182: 			}
183: 		} break;
184: 		case GDScriptParser::DataType::ENUM:
185: 			if (p_handle_metatype && p_datatype.is_meta_type) {
186: 				result.kind = GDScriptDataType::BUILTIN;
187: 				result.builtin_type = Variant::DICTIONARY;
188: 				break;
189: 			}
190: 
191: 			result.kind = GDScriptDataType::BUILTIN;
192: 			result.builtin_type = p_datatype.builtin_type;
193: 			break;
194: 		case GDScriptParser::DataType::RESOLVING:
195: 		case GDScriptParser::DataType::UNRESOLVED: {
196: 			ERR_PRINT("Parser bug: converting unresolved type.");
197: 			return GDScriptDataType();
198: 		}
199: 	}
