208: static bool _is_exact_type(const PropertyInfo &p_par_type, const GDScriptDataType &p_arg_type) {
209: 	if (!p_arg_type.has_type) {
210: 		return false;
211: 	}
212: 	if (p_par_type.type == Variant::NIL) {
213: 		return false;
214: 	}
215: 	if (p_par_type.type == Variant::OBJECT) {
216: 		if (p_arg_type.kind == GDScriptDataType::BUILTIN) {
217: 			return false;
218: 		}
219: 		StringName class_name;
220: 		if (p_arg_type.kind == GDScriptDataType::NATIVE) {
221: 			class_name = p_arg_type.native_type;
222: 		} else {
223: 			class_name = p_arg_type.native_type == StringName() ? p_arg_type.script_type->get_instance_base_type() : p_arg_type.native_type;
224: 		}
225: 		return p_par_type.class_name == class_name || ClassDB::is_parent_class(class_name, p_par_type.class_name);
226: 	} else {
227: 		if (p_arg_type.kind != GDScriptDataType::BUILTIN) {
228: 			return false;
229: 		}
230: 		return p_par_type.type == p_arg_type.builtin_type;
231: 	}
