234: static bool _can_use_validate_call(const MethodBind *p_method, const Vector<GDScriptCodeGenerator::Address> &p_arguments) {
235: 	if (p_method->is_vararg()) {
236: 		// Validated call won't work with vararg methods.
237: 		return false;
238: 	}
239: 	if (p_method->get_argument_count() != p_arguments.size()) {
240: 		// Validated call won't work with default arguments.
241: 		return false;
242: 	}
243: 	MethodInfo info;
244: 	ClassDB::get_method_info(p_method->get_instance_class(), p_method->get_name(), &info);
245: 	int i = 0;
246: 	for (List<PropertyInfo>::ConstIterator itr = info.arguments.begin(); itr != info.arguments.end(); ++itr, ++i) {
247: 		if (!_is_exact_type(*itr, p_arguments[i].type)) {
248: 			return false;
249: 		}
250: 	}
251: 	return true;
252: }
